```java
import java.util.ArrayList;
import java.util.LinkedList;
import java.util.List;
import java.util.Queue;

public class Elevator {

    public enum Direction {
        UP, DOWN, IDLE
    }

    public enum DoorStatus {
        OPEN, CLOSED
    }

    private int currentFloor;
    private Direction direction;
    private DoorStatus doorStatus;
    private final int minFloor;
    private final int maxFloor;
    private final Queue<Integer> destinationQueue; // Floors requested inside the elevator

    public Elevator(int minFloor, int maxFloor, int initialFloor) {
        if (initialFloor < minFloor || initialFloor > maxFloor) {
            throw new IllegalArgumentException("Initial floor must be within min and max floor range.");
        }
        this.minFloor = minFloor;
        this.maxFloor = maxFloor;
        this.currentFloor = initialFloor;
        this.direction = Direction.IDLE;
        this.doorStatus = DoorStatus.CLOSED;
        this.destinationQueue = new LinkedList<>();
        System.out.println("Elevator initialized at Floor " + currentFloor + ". Doors " + doorStatus + ".");
    }

    public int getCurrentFloor() {
        return currentFloor;
    }

    public Direction getDirection() {
        return direction;
    }

    public DoorStatus getDoorStatus() {
        return doorStatus;
    }

    // --- Core Elevator Operations ---

    public void requestFloor(int floor) {
        if (floor < minFloor || floor > maxFloor) {
            System.out.println("Invalid floor requested: " + floor + ". Must be between " + minFloor + " and " + maxFloor + ".");
            return;
        }
        if (!destinationQueue.contains(floor)) {
            destinationQueue.add(floor);
            System.out.println("Floor " + floor + " added to destination queue.");
            processRequests(); // Start/continue processing requests
        } else {
            System.out.println("Floor " + floor + " is already in the queue.");
        }
    }

    private void openDoors() {
        if (this.doorStatus == DoorStatus.CLOSED) {
            System.out.println("Opening doors at Floor " + currentFloor + "...");
            this.doorStatus = DoorStatus.OPEN;
            try { Thread.sleep(1000); } catch (InterruptedException e) { Thread.currentThread().interrupt(); } // Simulate delay
            System.out.println("Doors OPEN.");
        }
    }

    private void closeDoors() {
        if (this.doorStatus == DoorStatus.OPEN) {
            System.out.println("Closing doors at Floor " + currentFloor + "...");
            this.doorStatus = DoorStatus.CLOSED;
            try { Thread.sleep(1000); } catch (InterruptedException e) { Thread.currentThread().interrupt(); } // Simulate delay
            System.out.println("Doors CLOSED.");
        }
    }

    private void moveUp() {
        if (currentFloor < maxFloor) {
            this.direction = Direction.UP;
            closeDoors(); // Ensure doors are closed before moving
            System.out.println("Moving UP from Floor " + currentFloor + "...");
            currentFloor++;
            try { Thread.sleep(2000); } catch (InterruptedException e) { Thread.currentThread().interrupt(); } // Simulate travel time
            System.out.println("Arrived at Floor " + currentFloor + ".");
        } else {
            this.direction = Direction.IDLE;
            System.out.println("Already at top floor (" + maxFloor + "). Cannot move up.");
        }
    }

    private void moveDown() {
        if (currentFloor > minFloor) {
            this.direction = Direction.DOWN;
            closeDoors(); // Ensure doors are closed before moving
            System.out.println("Moving DOWN from Floor " + currentFloor + "...");
            currentFloor--;
            try { Thread.sleep(2000); } catch (InterruptedException e) { Thread.currentThread().interrupt(); } // Simulate travel time
            System.out.println("Arrived at Floor " + currentFloor + ".");
        } else {
            this.direction = Direction.IDLE;
            System.out.println("Already at bottom floor (" + minFloor + "). Cannot move down.");
        }
    }

    private void stop() {
        this.direction = Direction.IDLE;
        System.out.println("Elevator stopped at Floor " + currentFloor + ".");
        openDoors();
    }

    // --- Request Processing Logic ---

    public void processRequests() {
        if (destinationQueue.isEmpty()) {
            this.direction = Direction.IDLE;
            System.out.println("No more requests. Elevator is IDLE.");
            return;
        }

        // For simplicity, let's just process the next request in the queue
        // A real system would optimize this (e.g., process all requests in current direction first)
        Integer targetFloor = destinationQueue.peek(); // Get next target without removing it yet

        if (targetFloor == null) { // Should not happen if queue isn't empty, but for safety
             this.direction = Direction.IDLE;
             return;
        }

        if (currentFloor == targetFloor) {
            stop();
            destinationQueue.remove(); // Remove current target as it's reached
            System.out.println("Reached destination floor " + targetFloor + ".");
            try { Thread.sleep(3000); } catch (InterruptedException e) { Thread.currentThread().interrupt(); } // Stay open for a bit
            closeDoors();
            processRequests(); // Process next request
        } else if (currentFloor < targetFloor) {
            moveUp();
            processRequests(); // Continue moving until target is reached
        } else { // currentFloor > targetFloor
            moveDown();
            processRequests(); // Continue moving until target is reached
        }
    }

    public static void main(String[] args) {
        Elevator elevator = new Elevator(1, 10, 1); // Floors 1 to 10, starts at 1

        System.out.println("\n--- Scenario 1: Basic Up and Down ---");
        elevator.requestFloor(5); // Go up to 5
        elevator.requestFloor(2); // Then down to 2
        elevator.requestFloor(7); // Then up to 7

        System.out.println("\n--- Scenario 2: Invalid Request ---");
        elevator.requestFloor(12); // Invalid floor

        System.out.println("\n--- Scenario 3: Request current floor ---");
        elevator.requestFloor(7); // Already requested or at 7
    }
}
